'use client'

import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Skeleton } from '@/components/ui/skeleton'

import { MoreHorizontal, Pencil, Trash } from 'lucide-react'

import { useDepartmentsList } from '../hooks/useDepartmentsList'
import { useDepartmentActions } from '../hooks/useDepartmentActions'
import { Department } from '../types/departments.types'

interface DepartmentsTableProps {
  onEdit?: (department: Department) => void
}

export function DepartmentsTable({ onEdit }: DepartmentsTableProps) {
  const { departments, loading } = useDepartmentsList()
  const { confirmDelete, loading: isDeleting } = useDepartmentActions()

  if (loading) {
    return <DepartmentsTableSkeleton />
  }

  if (!departments?.length) {
    return (
      <div className="rounded-md border p-6 text-center text-sm text-muted-foreground">
        No departments found.
      </div>
    )
  }

  return (
    <div className="rounded-md border">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Title</TableHead>
            <TableHead>Jobs</TableHead>
            <TableHead align='right' >Actions</TableHead>
          </TableRow>
        </TableHeader>

        <TableBody>
          {departments.map((department) => (
            <TableRow key={department._id}>
              <TableCell className="font-medium">
                {department.title}
              </TableCell>

              <TableCell>
                {department.jobsCount ?? 0}
              </TableCell>

              <TableCell className="text-right">
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-8 w-8"
                    >
                      <MoreHorizontal className="h-4 w-4" />
                    </Button>
                  </DropdownMenuTrigger>

                  <DropdownMenuContent align="end">
                    <DropdownMenuItem
                      onClick={() => onEdit?.(department)}
                    >
                      <Pencil className="mr-2 h-4 w-4" />
                      Edit
                    </DropdownMenuItem>

                    <DropdownMenuItem
                      className="text-destructive"
                      disabled={isDeleting}
                      onClick={() => confirmDelete(department)}
                    >
                      <Trash className="mr-2 h-4 w-4" />
                      Delete
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  )
}

function DepartmentsTableSkeleton() {
  return (
    <div className="rounded-md border">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Name</TableHead>
            <TableHead>Members</TableHead>
            <TableHead>Status</TableHead>
            <TableHead />
          </TableRow>
        </TableHeader>

        <TableBody>
          {Array.from({ length: 5 }).map((_, i) => (
            <TableRow key={i}>
              <TableCell>
                <Skeleton className="h-4 w-40" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-4 w-10" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-5 w-16" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-8 w-8" />
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  )
}
